# Step 1: Create abstraction (Protocol) — commit, merge, done
# billing/abc.py
from typing import Protocol
from decimal import Decimal

class PaymentProcessor(Protocol):
    def process(self, amount: Decimal) -> "PaymentResult": ...

# Step 2: Old implementation satisfies the Protocol
# billing/legacy.py
class LegacyPaymentProcessor:
    def process(self, amount: Decimal) -> PaymentResult:
        return self.old_gateway.charge(amount)

# Step 3: New implementation behind the same Protocol
# billing/stripe_impl.py
class StripePaymentProcessor:
    def process(self, amount: Decimal) -> PaymentResult:
        return self._stripe.create_charge(amount)

# Step 4: Factory routes via flag
# billing/factory.py
from .flags import flags
def get_processor() -> PaymentProcessor:
    if flags.is_enabled("billing.use_stripe_v2"):
        return StripePaymentProcessor()
    return LegacyPaymentProcessor()

# Step 5 (cleanup ticket): After 100% rollout + stability confirmed
# - Delete billing/legacy.py
# - Remove flag "billing.use_stripe_v2" from provider
# - Replace factory with direct: return StripePaymentProcessor()
# - Remove PaymentProcessor Protocol if no longer needed elsewhere

# After full rollout of billing.use_stripe_v2, developer leaves:
def get_processor() -> PaymentProcessor:
    if flags.is_enabled("billing.use_stripe_v2"):  # always True now
        return StripePaymentProcessor()
    return LegacyPaymentProcessor()  # dead code, never reached
